// DocuSign Connect HMAC verification (HMAC-SHA256, base64), per DocuSign Connect docs:
// https://developers.docusign.com/platform/webhooks/connect/#hmac-message-signature-verification
// Requires the webhook trigger's 'rawBody' option enabled so the exact bytes DocuSign signed are available.
// No $env access available â€” secret is hardcoded here. Treat this workflow export as a secret.
const crypto = require('crypto')

const DOCUSIGN_WEBHOOK_SECRET = 'PASTE_DOCUSIGN_WEBHOOK_SECRET_HERE'

const item = $input.first().json
const rawBody = item.rawBody
const signatureHeader = item.headers['x-docusign-signature-1']

const valid = !!rawBody && !!signatureHeader && (() => {
  const expected = crypto.createHmac('sha256', DOCUSIGN_WEBHOOK_SECRET).update(rawBody).digest('base64')
  const a = Buffer.from(expected)
  const b = Buffer.from(signatureHeader)
  return a.length === b.length && crypto.timingSafeEqual(a, b)
})()

return [{ json: { ...item, signatureValid: valid } }]

// Mint a DocuSign JWT Grant access token. One-time setup already done: RSA keypair generated
// in DocuSign, consent granted via account-d.docusign.com/oauth/auth?...&scope=signature%20impersonation.
// This runs fresh on every execution â€” tokens are short-lived (~1hr) and not cached across runs.
const crypto = require('crypto')

const cfg = $input.first().json
const now = Math.floor(Date.now() / 1000)
const header = { alg: 'RS256', typ: 'JWT' }
const payload = {
  iss: cfg.docusignClientId,
  sub: cfg.docusignUserId,
  aud: cfg.docusignAuthServer,
  iat: now,
  exp: now + 3600,
  scope: 'signature impersonation',
}

const base64url = (obj) => Buffer.from(JSON.stringify(obj)).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
const unsigned = `${base64url(header)}.${base64url(payload)}`
const signature = crypto.sign('RSA-SHA256', Buffer.from(unsigned), cfg.docusignPrivateKey).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
const jwt = `${unsigned}.${signature}`

return [{ json: { ...cfg, jwtAssertion: jwt } }]

parameters.jsonBody:
={
  "query": "query FindOpenPullsByEmail($email: String!) { pulls(filter: { stage: { in: [VISITED, OUT, DUE_SOON, OVERDUE] }, clientId: { emails: { primaryEmail: { eq: $email } } } }) { edges { node { id name clientId { id } } } } }",
  "variables": { "email": "{{ $('DocuSign Connect Webhook').item.json.body.data.envelopeSummary.recipients.signers[0].email }}" }
}

={
  "query": "query ExistingContracts($id: ID!) { person(filter: { id: { eq: $id } }) { contracts { fileId } } }",
  "variables": { "id": "{{ $('Find Open Pulls By Signer Email').item.json.data.pulls.edges[0].node.clientId.id }}" }
}

={
  "query": "mutation AttachContract($pullId: ID!, $personId: ID!, $pullInput: PullUpdateInput!, $personInput: PersonUpdateInput!) { updatePull(id: $pullId, data: $pullInput) { id contractSigned } updatePerson(id: $personId, data: $personInput) { id } }",
  "variables": {
    "pullId": "{{ $('Find Open Pulls By Signer Email').item.json.data.pulls.edges[0].node.id }}",
    "personId": "{{ $('Find Open Pulls By Signer Email').item.json.data.pulls.edges[0].node.clientId.id }}",
    "pullInput": {
      "contractSigned": true,
      "signedContract": [ { "fileId": "{{ $('Upload PDF to Twenty (Pull field)').item.json.data.uploadFilesFieldFile.id }}", "label": "Signed Contract" } ]
    },
    "personInput": {
      "contracts": {{ JSON.stringify([...(($('Fetch Existing Person Contracts').item.json.data.person ?? {}).contracts ?? []).map(c => ({ fileId: c.fileId, label: 'Contract' })), { fileId: $('Upload PDF to Twenty (Pull field)').item.json.data.uploadFilesFieldFile.id, label: 'Contract' }]) }}
    }
  }
}

